eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   \"default\": () => (__WEBPACK_DEFAULT_EXPORT__),\n/* harmony export */   quizBank: () => (/* binding */ quizBank)\n/* harmony export */ });\nconst quizBank = [\n    // 第一单元：走进物联网\n    {\n        id: \"Q0101\",\n        lessonId: \"L01\",\n        type: \"single\",\n        question: \"物联网的英文缩写是什么？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"IoT\"\n            },\n            {\n                label: \"B\",\n                content: \"IT\"\n            },\n            {\n                label: \"C\",\n                content: \"IoP\"\n            },\n            {\n                label: \"D\",\n                content: \"NET\"\n            }\n        ],\n        answer: \"A\",\n        analysis: '物联网的英文是Internet of Things，缩写为IoT。其中\"I\"代表Internet，\"o\"代表of，\"T\"代表Things。',\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"物联网定义\"\n    },\n    {\n        id: \"Q0102\",\n        lessonId: \"L01\",\n        type: \"single\",\n        question: \"以下哪项不是物联网的三大特征？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"全面感知\"\n            },\n            {\n                label: \"B\",\n                content: \"可靠传输\"\n            },\n            {\n                label: \"C\",\n                content: \"高速计算\"\n            },\n            {\n                label: \"D\",\n                content: \"智能处理\"\n            }\n        ],\n        answer: \"C\",\n        analysis: '物联网的三大特征是：全面感知、可靠传输、智能处理。\"高速计算\"不是物联网的基本特征。',\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"物联网特征\"\n    },\n    {\n        id: \"Q0103\",\n        lessonId: \"L01\",\n        type: \"judge\",\n        question: \"物联网就是互联网，两者没有区别。\",\n        options: [\n            {\n                label: \"A\",\n                content: \"正确\"\n            },\n            {\n                label: \"B\",\n                content: \"错误\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"物联网与互联网有本质区别：互联网连接的是人与人，物联网连接的是物与物、人与物。物联网的信息来源是传感器自动采集，而互联网是人为输入。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"物联网与互联网的区别\"\n    },\n    {\n        id: \"Q0201\",\n        lessonId: \"L02\",\n        type: \"single\",\n        question: '\"物联网\"概念最早是在哪一年提出的？',\n        options: [\n            {\n                label: \"A\",\n                content: \"1999年\"\n            },\n            {\n                label: \"B\",\n                content: \"2005年\"\n            },\n            {\n                label: \"C\",\n                content: \"2010年\"\n            },\n            {\n                label: \"D\",\n                content: \"2015年\"\n            }\n        ],\n        answer: \"A\",\n        analysis: '1999年，Kevin Ashton首次提出\"物联网\"概念，认为物品也应该能够\"说话\"。',\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"物联网起源\"\n    },\n    {\n        id: \"Q0202\",\n        lessonId: \"L02\",\n        type: \"multiple\",\n        question: \"推动物联网发展的关键技术有哪些？（多选）\",\n        options: [\n            {\n                label: \"A\",\n                content: \"传感器技术\"\n            },\n            {\n                label: \"B\",\n                content: \"通信技术（5G等）\"\n            },\n            {\n                label: \"C\",\n                content: \"云计算\"\n            },\n            {\n                label: \"D\",\n                content: \"人工智能\"\n            }\n        ],\n        answer: [\n            \"A\",\n            \"B\",\n            \"C\",\n            \"D\"\n        ],\n        analysis: \"物联网发展依赖多项关键技术：传感器技术实现数据采集，通信技术（5G、NB-IoT）实现数据传输，云计算提供数据处理能力，人工智能实现智能分析决策。\",\n        difficulty: 2,\n        points: 3,\n        knowledgePoint: \"关键技术\"\n    },\n    {\n        id: \"Q0301\",\n        lessonId: \"L03\",\n        type: \"single\",\n        question: \"物联网三层架构中，负责数据采集的是哪一层？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"应用层\"\n            },\n            {\n                label: \"B\",\n                content: \"网络层\"\n            },\n            {\n                label: \"C\",\n                content: \"感知层\"\n            },\n            {\n                label: \"D\",\n                content: \"传输层\"\n            }\n        ],\n        answer: \"C\",\n        analysis: \"物联网三层架构：感知层负责数据采集和设备控制，网络层负责信息传输，应用层负责数据处理和智能应用。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"三层架构\"\n    },\n    {\n        id: \"Q0302\",\n        lessonId: \"L03\",\n        type: \"fill\",\n        question: \"物联网三层架构从下到上依次是：感知层、____层、应用层。\",\n        answer: \"网络\",\n        analysis: \"物联网三层架构从下到上依次是：感知层（数据采集）、网络层（信息传输）、应用层（数据处理和应用）。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"三层架构\"\n    },\n    {\n        id: \"Q0401\",\n        lessonId: \"L04\",\n        type: \"single\",\n        question: \"以下哪个不属于智能家居的应用？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"智能音箱\"\n            },\n            {\n                label: \"B\",\n                content: \"智能门锁\"\n            },\n            {\n                label: \"C\",\n                content: \"共享单车\"\n            },\n            {\n                label: \"D\",\n                content: \"智能灯泡\"\n            }\n        ],\n        answer: \"C\",\n        analysis: \"共享单车属于智慧交通应用，不属于智能家居。智能家居包括智能音箱、智能门锁、智能灯泡、智能空调等家庭设备。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"物联网应用场景\"\n    },\n    {\n        id: \"Q0402\",\n        lessonId: \"L04\",\n        type: \"multiple\",\n        question: \"物联网的主要应用领域包括哪些？（多选）\",\n        options: [\n            {\n                label: \"A\",\n                content: \"智能家居\"\n            },\n            {\n                label: \"B\",\n                content: \"智慧城市\"\n            },\n            {\n                label: \"C\",\n                content: \"智慧农业\"\n            },\n            {\n                label: \"D\",\n                content: \"智慧医疗\"\n            }\n        ],\n        answer: [\n            \"A\",\n            \"B\",\n            \"C\",\n            \"D\"\n        ],\n        analysis: \"物联网应用非常广泛，包括智能家居、智慧城市、智慧交通、智慧农业、智慧医疗、工业物联网等多个领域。\",\n        difficulty: 1,\n        points: 3,\n        knowledgePoint: \"物联网应用场景\"\n    },\n    {\n        id: \"Q0501\",\n        lessonId: \"L05\",\n        type: \"judge\",\n        question: \"边缘计算是将计算能力部署在网络边缘，可以降低延迟并保护数据隐私。\",\n        options: [\n            {\n                label: \"A\",\n                content: \"正确\"\n            },\n            {\n                label: \"B\",\n                content: \"错误\"\n            }\n        ],\n        answer: \"A\",\n        analysis: \"边缘计算将计算能力部署在靠近数据源的网络边缘，优势包括：低延迟（本地处理）、省带宽（减少上传）、高可靠（断网也能工作）、隐私保护（敏感数据不出本地）。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"边缘计算\"\n    },\n    // 第二单元：感知与识别\n    {\n        id: \"Q0601\",\n        lessonId: \"L06\",\n        type: \"single\",\n        question: \"传感器的主要功能是什么？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"存储数据\"\n            },\n            {\n                label: \"B\",\n                content: \"传输数据\"\n            },\n            {\n                label: \"C\",\n                content: \"检测并转换信息\"\n            },\n            {\n                label: \"D\",\n                content: \"显示数据\"\n            }\n        ],\n        answer: \"C\",\n        analysis: \"传感器是一种检测装置，能感受到被测量的信息，并将检测到的信息转换成电信号或其他形式输出。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"传感器定义\"\n    },\n    {\n        id: \"Q0602\",\n        lessonId: \"L06\",\n        type: \"fill\",\n        question: \"传感器通常由敏感元件、____元件和信号调理电路三部分组成。\",\n        answer: \"转换\",\n        analysis: \"传感器的组成：敏感元件（感知物理量）→ 转换元件（转换为电信号）→ 信号调理电路（放大、滤波等处理）。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"传感器组成\"\n    },\n    {\n        id: \"Q0701\",\n        lessonId: \"L07\",\n        type: \"single\",\n        question: \"手机自动调节屏幕亮度使用的是哪种传感器？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"温度传感器\"\n            },\n            {\n                label: \"B\",\n                content: \"光敏传感器\"\n            },\n            {\n                label: \"C\",\n                content: \"声音传感器\"\n            },\n            {\n                label: \"D\",\n                content: \"运动传感器\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"光敏传感器可以检测环境光照强度，手机根据光照强度自动调节屏幕亮度，在强光下提高亮度，在暗光下降低亮度。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"光敏传感器应用\"\n    },\n    {\n        id: \"Q0702\",\n        lessonId: \"L07\",\n        type: \"multiple\",\n        question: \"以下哪些是常见的传感器类型？（多选）\",\n        options: [\n            {\n                label: \"A\",\n                content: \"温度传感器\"\n            },\n            {\n                label: \"B\",\n                content: \"湿度传感器\"\n            },\n            {\n                label: \"C\",\n                content: \"光敏传感器\"\n            },\n            {\n                label: \"D\",\n                content: \"运动传感器\"\n            }\n        ],\n        answer: [\n            \"A\",\n            \"B\",\n            \"C\",\n            \"D\"\n        ],\n        analysis: \"常见传感器包括：温度传感器、湿度传感器、光敏传感器、运动传感器（加速度传感器）、声音传感器等。\",\n        difficulty: 1,\n        points: 3,\n        knowledgePoint: \"常见传感器\"\n    },\n    {\n        id: \"Q0801\",\n        lessonId: \"L08\",\n        type: \"single\",\n        question: \"RFID的中文名称是什么？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"射频识别\"\n            },\n            {\n                label: \"B\",\n                content: \"蓝牙识别\"\n            },\n            {\n                label: \"C\",\n                content: \"红外识别\"\n            },\n            {\n                label: \"D\",\n                content: \"图像识别\"\n            }\n        ],\n        answer: \"A\",\n        analysis: \"RFID是Radio Frequency Identification的缩写，中文名称为射频识别，是一种无线通信技术。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"RFID定义\"\n    },\n    {\n        id: \"Q0802\",\n        lessonId: \"L08\",\n        type: \"multiple\",\n        question: \"RFID系统由哪些部分组成？（多选）\",\n        options: [\n            {\n                label: \"A\",\n                content: \"RFID标签\"\n            },\n            {\n                label: \"B\",\n                content: \"RFID读写器\"\n            },\n            {\n                label: \"C\",\n                content: \"天线\"\n            },\n            {\n                label: \"D\",\n                content: \"数据库系统\"\n            }\n        ],\n        answer: [\n            \"A\",\n            \"B\",\n            \"C\",\n            \"D\"\n        ],\n        analysis: \"RFID系统组成：RFID标签（存储信息）、RFID读写器（读取/写入数据）、天线（发射和接收信号）、数据库系统（存储和管理数据）。\",\n        difficulty: 2,\n        points: 3,\n        knowledgePoint: \"RFID组成\"\n    },\n    {\n        id: \"Q0901\",\n        lessonId: \"L09\",\n        type: \"judge\",\n        question: \"二维码比一维条形码存储的信息容量更大。\",\n        options: [\n            {\n                label: \"A\",\n                content: \"正确\"\n            },\n            {\n                label: \"B\",\n                content: \"错误\"\n            }\n        ],\n        answer: \"A\",\n        analysis: \"二维码在水平和垂直两个方向都能存储信息，信息容量远大于一维条形码。二维码还可以存储汉字、图片等，容错能力也更强。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"二维码特点\"\n    },\n    {\n        id: \"Q0902\",\n        lessonId: \"L09\",\n        type: \"single\",\n        question: \"共享单车开锁使用的是哪种识别技术？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"RFID\"\n            },\n            {\n                label: \"B\",\n                content: \"二维码\"\n            },\n            {\n                label: \"C\",\n                content: \"条形码\"\n            },\n            {\n                label: \"D\",\n                content: \"人脸识别\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"共享单车使用二维码识别技术，用户用手机APP扫描车身上的二维码即可开锁。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"二维码应用\"\n    },\n    {\n        id: \"Q1001\",\n        lessonId: \"L10\",\n        type: \"single\",\n        question: \"人脸识别属于哪种识别技术？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"条码识别\"\n            },\n            {\n                label: \"B\",\n                content: \"图像识别\"\n            },\n            {\n                label: \"C\",\n                content: \"语音识别\"\n            },\n            {\n                label: \"D\",\n                content: \"RFID识别\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"人脸识别是图像识别的一种应用，通过计算机分析人脸图像特征，实现身份识别。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"图像识别\"\n    },\n    {\n        id: \"Q1101\",\n        lessonId: \"L11\",\n        type: \"single\",\n        question: \"智能音箱（如小爱同学）能听懂语音指令，使用的是什么技术？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"图像识别\"\n            },\n            {\n                label: \"B\",\n                content: \"语音识别\"\n            },\n            {\n                label: \"C\",\n                content: \"条码识别\"\n            },\n            {\n                label: \"D\",\n                content: \"RFID识别\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"智能音箱使用语音识别技术，将用户的语音转换为文字或命令，然后执行相应操作。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"语音识别应用\"\n    },\n    // 第三单元：传感器与数据采集\n    {\n        id: \"Q1201\",\n        lessonId: \"L12\",\n        type: \"single\",\n        question: \"DHT11传感器可以测量哪些数据？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"仅温度\"\n            },\n            {\n                label: \"B\",\n                content: \"仅湿度\"\n            },\n            {\n                label: \"C\",\n                content: \"温度和湿度\"\n            },\n            {\n                label: \"D\",\n                content: \"光照强度\"\n            }\n        ],\n        answer: \"C\",\n        analysis: \"DHT11是一款常用的温湿度传感器，可以同时测量温度和湿度，温度测量范围0-50\\xb0C，湿度测量范围20-90%RH。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"温湿度传感器\"\n    },\n    {\n        id: \"Q1202\",\n        lessonId: \"L12\",\n        type: \"judge\",\n        question: \"DHT22比DHT11的测量精度更高。\",\n        options: [\n            {\n                label: \"A\",\n                content: \"正确\"\n            },\n            {\n                label: \"B\",\n                content: \"错误\"\n            }\n        ],\n        answer: \"A\",\n        analysis: \"DHT22的精度优于DHT11。DHT22温度精度\\xb10.5\\xb0C，湿度精度\\xb12%RH；而DHT11温度精度\\xb12\\xb0C，湿度精度\\xb15%RH。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"温湿度传感器精度\"\n    },\n    {\n        id: \"Q1301\",\n        lessonId: \"L13\",\n        type: \"single\",\n        question: \"光敏电阻的阻值与光照强度的关系是？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"光照越强，阻值越大\"\n            },\n            {\n                label: \"B\",\n                content: \"光照越强，阻值越小\"\n            },\n            {\n                label: \"C\",\n                content: \"阻值与光照无关\"\n            },\n            {\n                label: \"D\",\n                content: \"阻值始终不变\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"光敏电阻的阻值随光照强度变化：光照强时阻值小，光照弱时阻值大。利用这一特性可以检测环境光照强度。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"光敏电阻原理\"\n    },\n    {\n        id: \"Q1401\",\n        lessonId: \"L14\",\n        type: \"single\",\n        question: \"手机横竖屏自动切换使用的是哪种传感器？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"温度传感器\"\n            },\n            {\n                label: \"B\",\n                content: \"光敏传感器\"\n            },\n            {\n                label: \"C\",\n                content: \"加速度传感器\"\n            },\n            {\n                label: \"D\",\n                content: \"声音传感器\"\n            }\n        ],\n        answer: \"C\",\n        analysis: \"加速度传感器（运动传感器）可以检测手机在三个方向上的加速度，根据加速度判断手机方向，实现横竖屏自动切换。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"加速度传感器应用\"\n    },\n    {\n        id: \"Q1501\",\n        lessonId: \"L15\",\n        type: \"single\",\n        question: \"根据奈奎斯特采样定理，采样频率应该大于信号最高频率的多少倍？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"1倍\"\n            },\n            {\n                label: \"B\",\n                content: \"2倍\"\n            },\n            {\n                label: \"C\",\n                content: \"3倍\"\n            },\n            {\n                label: \"D\",\n                content: \"4倍\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"奈奎斯特采样定理：采样频率应大于信号最高频率的2倍，这样才能无失真地还原原始信号。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"采样定理\"\n    },\n    {\n        id: \"Q1502\",\n        lessonId: \"L15\",\n        type: \"fill\",\n        question: \"CD音质的采样频率是____Hz。\",\n        answer: \"44100\",\n        analysis: \"CD音质的采样频率是44100Hz（44.1kHz），即每秒采样44100次，可以高质量还原音频信号。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"音频采样\"\n    },\n    {\n        id: \"Q1601\",\n        lessonId: \"L16\",\n        type: \"single\",\n        question: \"以下哪种图表最适合展示数据的变化趋势？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"饼图\"\n            },\n            {\n                label: \"B\",\n                content: \"柱状图\"\n            },\n            {\n                label: \"C\",\n                content: \"折线图\"\n            },\n            {\n                label: \"D\",\n                content: \"散点图\"\n            }\n        ],\n        answer: \"C\",\n        analysis: \"折线图通过连接数据点展示数据的变化趋势，适合展示时间序列数据或连续变化的数据。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"数据可视化\"\n    },\n    // 第四单元：物联网通信\n    {\n        id: \"Q1701\",\n        lessonId: \"L17\",\n        type: \"single\",\n        question: \"蓝牙的有效传输距离一般在多少米以内？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"1米\"\n            },\n            {\n                label: \"B\",\n                content: \"10米\"\n            },\n            {\n                label: \"C\",\n                content: \"100米\"\n            },\n            {\n                label: \"D\",\n                content: \"1000米\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"蓝牙是一种短距离无线通信技术，有效传输距离一般在10米左右，蓝牙5.0可以扩展到100米以上。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"蓝牙传输距离\"\n    },\n    {\n        id: \"Q1702\",\n        lessonId: \"L17\",\n        type: \"multiple\",\n        question: \"蓝牙的特点包括哪些？（多选）\",\n        options: [\n            {\n                label: \"A\",\n                content: \"短距离传输\"\n            },\n            {\n                label: \"B\",\n                content: \"低功耗\"\n            },\n            {\n                label: \"C\",\n                content: \"点对点通信\"\n            },\n            {\n                label: \"D\",\n                content: \"需要配对连接\"\n            }\n        ],\n        answer: [\n            \"A\",\n            \"B\",\n            \"C\",\n            \"D\"\n        ],\n        analysis: \"蓝牙的特点：短距离无线传输（10-100米）、低功耗、点对点通信、使用前需要配对连接。\",\n        difficulty: 1,\n        points: 3,\n        knowledgePoint: \"蓝牙特点\"\n    },\n    {\n        id: \"Q1801\",\n        lessonId: \"L18\",\n        type: \"judge\",\n        question: \"Wi-Fi的传输距离比蓝牙更远，传输速度也更快。\",\n        options: [\n            {\n                label: \"A\",\n                content: \"正确\"\n            },\n            {\n                label: \"B\",\n                content: \"错误\"\n            }\n        ],\n        answer: \"A\",\n        analysis: \"Wi-Fi传输距离可达几十到几百米，传输速度可达几百Mbps到几Gbps；蓝牙传输距离约10米，传输速度1-3Mbps。Wi-Fi在距离和速度上都优于蓝牙。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"Wi-Fi与蓝牙对比\"\n    },\n    {\n        id: \"Q1901\",\n        lessonId: \"L19\",\n        type: \"single\",\n        question: \"MQTT协议采用的是什么通信模式？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"请求-响应模式\"\n            },\n            {\n                label: \"B\",\n                content: \"发布-订阅模式\"\n            },\n            {\n                label: \"C\",\n                content: \"点对点模式\"\n            },\n            {\n                label: \"D\",\n                content: \"广播模式\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"MQTT采用发布/订阅模式：发布者发布消息到Broker，Broker将消息推送给订阅了该Topic的订阅者。这种模式解耦了消息发送者和接收者。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"MQTT通信模式\"\n    },\n    {\n        id: \"Q1902\",\n        lessonId: \"L19\",\n        type: \"fill\",\n        question: \"MQTT协议中，消息的分类通过____来区分，类似于电视频道。\",\n        answer: \"Topic\",\n        analysis: \"MQTT使用Topic（主题）来分类消息，类似电视频道。发布者发布消息到特定Topic，订阅者订阅Topic接收消息。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"MQTT Topic\"\n    },\n    {\n        id: \"Q2001\",\n        lessonId: \"L20\",\n        type: \"single\",\n        question: \"数据传输方式中，可以同时双向传输的是哪种？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"单工\"\n            },\n            {\n                label: \"B\",\n                content: \"半双工\"\n            },\n            {\n                label: \"C\",\n                content: \"全双工\"\n            },\n            {\n                label: \"D\",\n                content: \"广播\"\n            }\n        ],\n        answer: \"C\",\n        analysis: \"全双工可以同时进行双向传输（如电话）；半双工可以双向传输但不能同时进行（如对讲机）；单工只能单向传输（如广播）。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"数据传输方式\"\n    },\n    {\n        id: \"Q2101\",\n        lessonId: \"L21\",\n        type: \"single\",\n        question: \"物联网网关的主要作用是什么？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"存储数据\"\n            },\n            {\n                label: \"B\",\n                content: \"显示数据\"\n            },\n            {\n                label: \"C\",\n                content: \"协议转换和数据转发\"\n            },\n            {\n                label: \"D\",\n                content: \"供电\"\n            }\n        ],\n        answer: \"C\",\n        analysis: \"网关是连接不同网络的设备，主要作用是协议转换（将传感器协议转换为互联网协议）和数据转发（将数据传输到云端）。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"网关功能\"\n    },\n    {\n        id: \"Q2201\",\n        lessonId: \"L22\",\n        type: \"multiple\",\n        question: \"边缘计算的优势有哪些？（多选）\",\n        options: [\n            {\n                label: \"A\",\n                content: \"低延迟\"\n            },\n            {\n                label: \"B\",\n                content: \"节省带宽\"\n            },\n            {\n                label: \"C\",\n                content: \"高可靠性\"\n            },\n            {\n                label: \"D\",\n                content: \"隐私保护\"\n            }\n        ],\n        answer: [\n            \"A\",\n            \"B\",\n            \"C\",\n            \"D\"\n        ],\n        analysis: \"边缘计算的优势：低延迟（本地处理快）、节省带宽（减少数据上传）、高可靠（断网也能工作）、隐私保护（敏感数据不出本地）。\",\n        difficulty: 2,\n        points: 3,\n        knowledgePoint: \"边缘计算优势\"\n    },\n    // 第五单元：物联网应用\n    {\n        id: \"Q2301\",\n        lessonId: \"L23\",\n        type: \"single\",\n        question: \"智能家居中，多个设备按照规则自动联动运行，这叫什么？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"远程控制\"\n            },\n            {\n                label: \"B\",\n                content: \"语音控制\"\n            },\n            {\n                label: \"C\",\n                content: \"场景联动\"\n            },\n            {\n                label: \"D\",\n                content: \"定时控制\"\n            }\n        ],\n        answer: \"C\",\n        analysis: \"场景联动是指多个智能设备按照预设规则自动协同工作。例如回家场景：门锁打开后，灯光、空调、窗帘自动联动。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"场景联动\"\n    },\n    {\n        id: \"Q2302\",\n        lessonId: \"L23\",\n        type: \"judge\",\n        question: \"智能家居系统必须连接互联网才能工作。\",\n        options: [\n            {\n                label: \"A\",\n                content: \"正确\"\n            },\n            {\n                label: \"B\",\n                content: \"错误\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"智能家居系统不一定必须连接互联网。本地网关可以实现局域网内的设备控制和联动，只有需要远程控制或云服务时才需要连接互联网。\",\n        difficulty: 2,\n        points: 2,\n        knowledgePoint: \"智能家居工作模式\"\n    },\n    {\n        id: \"Q2401\",\n        lessonId: \"L24\",\n        type: \"single\",\n        question: \"智慧农业中，土壤湿度传感器可以用于实现什么功能？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"自动施肥\"\n            },\n            {\n                label: \"B\",\n                content: \"智能灌溉\"\n            },\n            {\n                label: \"C\",\n                content: \"病虫害预警\"\n            },\n            {\n                label: \"D\",\n                content: \"光照调节\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"土壤湿度传感器检测土壤湿度，当湿度低于阈值时自动开启灌溉系统，实现智能灌溉。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"智慧农业应用\"\n    },\n    {\n        id: \"Q2501\",\n        lessonId: \"L25\",\n        type: \"single\",\n        question: \"ETC不停车收费使用的是什么技术？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"二维码\"\n            },\n            {\n                label: \"B\",\n                content: \"RFID\"\n            },\n            {\n                label: \"C\",\n                content: \"蓝牙\"\n            },\n            {\n                label: \"D\",\n                content: \"Wi-Fi\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"ETC（Electronic Toll Collection）使用RFID技术。车载OBU（车载单元）与路侧RSU（路侧单元）通过射频通信实现不停车收费。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"ETC技术\"\n    },\n    {\n        id: \"Q2601\",\n        lessonId: \"L26\",\n        type: \"multiple\",\n        question: \"智能监控系统可以实现哪些功能？（多选）\",\n        options: [\n            {\n                label: \"A\",\n                content: \"人脸识别\"\n            },\n            {\n                label: \"B\",\n                content: \"移动侦测\"\n            },\n            {\n                label: \"C\",\n                content: \"异常报警\"\n            },\n            {\n                label: \"D\",\n                content: \"远程查看\"\n            }\n        ],\n        answer: [\n            \"A\",\n            \"B\",\n            \"C\",\n            \"D\"\n        ],\n        analysis: \"智能监控系统功能：人脸识别（识别陌生人）、移动侦测（检测画面变化）、异常报警（发送报警信息）、远程查看（手机远程查看监控画面）。\",\n        difficulty: 1,\n        points: 3,\n        knowledgePoint: \"智能监控功能\"\n    },\n    {\n        id: \"Q2701\",\n        lessonId: \"L27\",\n        type: \"single\",\n        question: \"将多个物联网子系统整合为一个协调工作的整体，这叫什么？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"系统集成\"\n            },\n            {\n                label: \"B\",\n                content: \"数据采集\"\n            },\n            {\n                label: \"C\",\n                content: \"设备控制\"\n            },\n            {\n                label: \"D\",\n                content: \"网络传输\"\n            }\n        ],\n        answer: \"A\",\n        analysis: \"系统集成是将多个子系统整合为一个协调工作的整体系统，实现数据共享、统一管理。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"系统集成定义\"\n    },\n    // 第六单元：物联网安全\n    {\n        id: \"Q2801\",\n        lessonId: \"L28\",\n        type: \"single\",\n        question: \"以下哪项是物联网设备常见的安全风险？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"弱密码被破解\"\n            },\n            {\n                label: \"B\",\n                content: \"设备电量充足\"\n            },\n            {\n                label: \"C\",\n                content: \"网络信号良好\"\n            },\n            {\n                label: \"D\",\n                content: \"设备正常运行\"\n            }\n        ],\n        answer: \"A\",\n        analysis: \"物联网设备常见安全风险包括：弱密码被破解、设备固件漏洞、设备被劫持、数据泄露、隐私侵犯等。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"物联网安全风险\"\n    },\n    {\n        id: \"Q2802\",\n        lessonId: \"L28\",\n        type: \"multiple\",\n        question: \"物联网安全风险包括哪些方面？（多选）\",\n        options: [\n            {\n                label: \"A\",\n                content: \"设备安全\"\n            },\n            {\n                label: \"B\",\n                content: \"网络安全\"\n            },\n            {\n                label: \"C\",\n                content: \"数据安全\"\n            },\n            {\n                label: \"D\",\n                content: \"应用安全\"\n            }\n        ],\n        answer: [\n            \"A\",\n            \"B\",\n            \"C\",\n            \"D\"\n        ],\n        analysis: \"物联网安全风险涉及多个层面：设备安全（弱密码、固件漏洞）、网络安全（数据窃听、协议漏洞）、数据安全（数据泄露、隐私侵犯）、应用安全（权限滥用）。\",\n        difficulty: 2,\n        points: 3,\n        knowledgePoint: \"安全风险类型\"\n    },\n    {\n        id: \"Q2901\",\n        lessonId: \"L29\",\n        type: \"single\",\n        question: \"将敏感信息部分隐藏或加密处理，这叫什么？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"数据备份\"\n            },\n            {\n                label: \"B\",\n                content: \"数据脱敏\"\n            },\n            {\n                label: \"C\",\n                content: \"数据压缩\"\n            },\n            {\n                label: \"D\",\n                content: \"数据传输\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"数据脱敏是将敏感信息部分隐藏或加密处理，保护个人隐私。例如：手机号显示为138****1234。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"数据脱敏\"\n    },\n    {\n        id: \"Q3001\",\n        lessonId: \"L30\",\n        type: \"multiple\",\n        question: \"强密码应该具备哪些特点？（多选）\",\n        options: [\n            {\n                label: \"A\",\n                content: \"长度足够（≥8位）\"\n            },\n            {\n                label: \"B\",\n                content: \"包含大小写字母\"\n            },\n            {\n                label: \"C\",\n                content: \"包含数字\"\n            },\n            {\n                label: \"D\",\n                content: \"包含特殊符号\"\n            }\n        ],\n        answer: [\n            \"A\",\n            \"B\",\n            \"C\",\n            \"D\"\n        ],\n        analysis: \"强密码应该：长度≥8位、包含大小写字母、包含数字、包含特殊符号，且定期更换，不使用常见词汇。\",\n        difficulty: 1,\n        points: 3,\n        knowledgePoint: \"强密码特点\"\n    },\n    {\n        id: \"Q3002\",\n        lessonId: \"L30\",\n        type: \"single\",\n        question: \"使用密码加上验证码/指纹/人脸进行双重验证，这叫什么？\",\n        options: [\n            {\n                label: \"A\",\n                content: \"单因素认证\"\n            },\n            {\n                label: \"B\",\n                content: \"双重认证\"\n            },\n            {\n                label: \"C\",\n                content: \"无认证\"\n            },\n            {\n                label: \"D\",\n                content: \"匿名认证\"\n            }\n        ],\n        answer: \"B\",\n        analysis: \"双重认证（2FA）是指使用两种不同类型的认证方式，如密码+验证码、密码+指纹等，比单因素认证更安全。\",\n        difficulty: 1,\n        points: 2,\n        knowledgePoint: \"双重认证\"\n    }\n];\n/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = (quizBank);\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/quiz/index.ts\n");

